import { reportHandoff } from "../analytics.js";
import { runBrowserHandoff } from "../browserHandoff.js";
import { getConfig, hasCredentials } from "../config.js";
import { focusApp, getFrontmostApp } from "./login.js";
const OPEN_TRACE_PLAN_TIMEOUT_MS = 30 * 60 * 1000;
const RESPONSE_HTML = `<html>
<body style="margin:0;background:#f8fafc;color:#0f172a;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden">
  <div style="text-align:center;max-width:400px">
    <h1 style="font-size:24px;font-weight:600;margin:0 0 16px 0">Bitfab</h1>
    <p style="margin:0;color:#059669">Trace plan recorded! You can close this window.</p>
    <button onclick="window.close()" style="margin-top:16px;padding:8px 16px;background:#0f172a;color:white;border:none;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer">Close Window</button>
  </div>
</body>
</html>`;
function parseStatus(raw) {
    return raw === "confirmed" ? "confirmed" : "cancelled";
}
/**
 * Open the trace plan confirmation page in the browser and block until the
 * user confirms or cancels. Races the loopback HTTP callback and a server-
 * polled ticket so it works across SSH, Docker, WSL, and cloud IDEs.
 *
 * Mirrors `runStartDataset` — same channel abstraction, different ticket
 * kind and target page.
 */
export async function runOpenTracePlan(platform, pluginVersion) {
    const args = process.argv.slice(2);
    const planId = args[0];
    if (!planId) {
        console.error("Usage: openTracePlan <planId>");
        console.error("Plan id is required.");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    const previousApp = getFrontmostApp();
    const loopbackRoute = {
        path: "/done",
        handle: (params, res, resolve) => {
            res.writeHead(200, { "Content-Type": "text/html" });
            res.end(RESPONSE_HTML);
            resolve({
                status: parseStatus(params.get("status")),
                isFetch: params.get("isFetch") === "true",
            });
        },
    };
    try {
        const { value, wonBy, loopbackAvailable, ticketAvailable } = await runBrowserHandoff({
            serviceUrl: config.serviceUrl,
            ticketKind: "tracePlan.confirm",
            ticketBearer: config.apiKey ?? undefined,
            timeoutMs: OPEN_TRACE_PLAN_TIMEOUT_MS,
            ticketTtlSeconds: OPEN_TRACE_PLAN_TIMEOUT_MS / 1000,
            buildUrl: ({ port, ticketId }) => {
                const url = new URL(`${config.serviceUrl}/trace-plan/${encodeURIComponent(planId)}`);
                if (port !== null) {
                    url.searchParams.set("callbackPort", String(port));
                }
                if (ticketId !== null) {
                    url.searchParams.set("ticket", ticketId);
                }
                return url.toString();
            },
            loopbackRoutes: [loopbackRoute],
        });
        const { status, isFetch } = value;
        if (status === "confirmed") {
            console.log(`Trace plan confirmed [via ${wonBy}]`);
        }
        else {
            console.log(`Trace plan cancelled [via ${wonBy}]`);
        }
        if (config.apiKey) {
            await reportHandoff(config.apiKey, pluginVersion, platform, {
                flow: "tracePlan.confirm",
                wonBy: wonBy,
                loopbackAvailable,
                ticketAvailable,
            });
        }
        if (isFetch) {
            focusApp(previousApp);
        }
        process.exit(0);
    }
    catch (err) {
        console.error(err.message);
        process.exit(1);
    }
}
